var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"후아, 죽다 살아나니까 이 더러운 길바닥이 레드 카펫으로 보이네.","JPN":"はあ、死にかけた後だからか、この汚い道がレッドカーペットに見えるな。","ENG":"Phew, it feels like I'm walking on a red carpet even on this nasty road now that I've made it out alive.","TWN":"呼！真是九死一生，連這骯髒的路面看起來都像紅地毯呢！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"누가 아니래. 우리 이 정도면 베테랑 용병 아냐?","JPN":"だな。俺らももはやベテラン傭兵じゃないか？","ENG":"Tell me about it. If this doesn't make us veteran mercenaries, I don't know what will.","TWN":"就是說，我們這種程度根本就是老鳥傭兵吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"업무 종료. 약속했던 대금 지불을 요구합니다, 휴먼.","JPN":"業務終了。約束した代金の支払いを要求します、ヒューマン。","ENG":"The job is done. I request payment as promised, human.","TWN":"業務完成。請支付約定的款項，人類。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"수고했다. 돈이라면 여기 봉투 안에 있어.","JPN":"ご苦労様。金ならこの封筒の中だ。","ENG":"Good job. The money's in this envelope.","TWN":"辛苦了，錢就在這個信封袋裡。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 주기 전에 한 가지 묻고 싶군. 괜찮겠나.","JPN":"しかし、渡す前に一つ聞きたい。いいか？","ENG":"But before I pay you, I'd like to ask just one question. Is that all right?","TWN":"但在你拿走前，我想問你一個問題，可以嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제가 대답해 드릴 수 있는 질문이라면.","JPN":"答えられる質問であれば。","ENG":"Certainly. Assuming it is a question that I can answer.","TWN":"我回答得出來的話。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"너는……. 카운터인가?","JPN":"あんたは……カウンターか？","ENG":"Are you… a Counter?","TWN":"你是……制裁者嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그 질문에 함축적인 의미가 있다는 전제로 대답드리겠습니다.","JPN":"その質問には隠された意図があることを前提にお答えします。","ENG":"I can sense your \\"one\\" question actually involves many. But my answer is simple.","TWN":"我會在這個問題別有用意的前提下回答你。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 기계입니다. 이상입니다.","JPN":"私は機械です。以上です。","ENG":"I am a machine. That is all.","TWN":"我是機器，以上。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"안드로이드라면 그라운드 원에서 본 적 있어.","JPN":"アンドロイドならグラウンド・ワンで見たことがある。","ENG":"Well, I've seen androids in Ground One before.","TWN":"人形機器人的話，我在G1有看過。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 그 중에서도 트럭을 집어던지는 기종이 있다는 얘기는 못 들었다.","JPN":"しかし、その中にトラックを投げつける機種があるなんて話は聞いていない。","ENG":"But none of them could throw a truck, to my knowledge.","TWN":"但我沒聽說過當中有會扔卡車的機種。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"물론입니다. 아무리 설명해도 휴먼들은 카운터라고 이해하더군요.","JPN":"もちろんです。いくら説明してもヒューマンたちはカウンターだと理解してしまいます。","ENG":"Of course. No matter how much I explain, humans simply believe that I'm a Counter.","TWN":"當然。因為無論怎麼解釋，人類都只會理解爲制裁者。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……최근 만난 한 명을 제외하면 말입니다.","JPN":"……最近会った一人を除けば、ですが。","ENG":"…Except one person I recently met.","TWN":"……除了我最近認識的那個人。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"몇 차례 시도 후, 의문을 표한 휴먼들을 설득하려는 시도는 포기했습니다.","JPN":"何度か試みた結果、疑問を示したヒューマンたちを説得するのは諦めました。","ENG":"After several attempts, I've given up on trying to convince humans otherwise.","TWN":"幾次嘗試後，我已經放棄試圖說服表示疑問的人類。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"설득해도 저에게 리턴은 없으니까요. 결국 눈으로 확인하지 않으면 못 믿더군요.","JPN":"説得しても私が得することはありません。結局、自身の目で確認できなければ信じてくれないのです。","ENG":"I have nothing to gain from it, after all. Humans never seem to believe anything they don't witness with their own eyes.","TWN":"因為根本就是對牛彈琴，若非親眼確認，人類是不會相信的。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"신기하지 않습니까. 혁신적인 구조의 기계보다 카운터라고 받아들이는 경향이.","JPN":"不思議だと思いませんか？　革新的な構造の機械よりも、カウンターだと受け止めてしまう傾向があるのです。","ENG":"Is it not fascinating? They're more willing to accept that I'm a Counter than an innovative, intricate machine.","TWN":"不覺得很神奇嗎。人類情願接受制裁者的這個說法，也不願相信有著革新架構的機器。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……S급 카운터라는 소문도 우습긴 했지만, 실물은 더 충격적이군.","JPN":"……S級カウンターという噂も笑えたが、実際はもっと衝撃的だったな。","ENG":"…I always thought the rumors about you being a Grade-S Counter was outlandish, but the truth is even more shocking.","TWN":"……雖然S級制裁者的傳聞也很可笑，但現實更令人震驚。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"누가 너 같은 기계를 만든 거지? 퓨처 앳 워인가?","JPN":"誰があんたのような機械を作ったんだ？　フューチャーアットウォーか？","ENG":"So who invented a machine like you? Was it Future-at-War?","TWN":"是誰創造你的？天啟兵器嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"구체적으로 답변드리면, <color=#ffd34c>저</color>는 퓨처 앳 워에서 생산된 시제품이 맞습니다.","JPN":"具体的にお答えしますと、<color=#ffd34c>私</color>はフューチャーアットウォーで生産された試作品です。","ENG":"To be precise, <color=#ffd34c>I</color> am indeed a prototype created by Future-at-War.","TWN":"具體來說，<color=#ffd34c>我</color>是天啟兵器生產的試用品。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 이 프레임은 억지로 떠맡았죠. 제 의사와 관계없이 말입니다.","JPN":"しかし、このフレームは無理やり引き受けました。私の意思とは関係なくです。","ENG":"But as for this frame, it was forced upon me. I had no choice on the matter.","TWN":"但是這副軀殼是硬塞給我的，與我的意願無關。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"아, 교관님. 마침 그 애랑 같이 계셨군요. 한참 찾았어요.","JPN":"あ、教官。ちょうどその子と一緒にいたんですね。探しましたよ。","ENG":"Ah, Instructor Kang. I'm glad it just so happens you're with the girl. I've been looking for her everywhere.","TWN":"喔，教官，這麼巧，你和她在一起，我找她找好久。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저한테 용무 있습니까, 휴먼?","JPN":"私にご用ですか、ヒューマン？","ENG":"Did you have business with me, human?","TWN":"人類，你找我有什麼事嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"그래. 레이첼이 너한테 전해 달라더라. 4번가에 있는 사무실로 오라고.","JPN":"ああ。レイチェルが伝えてほしいと頼まれたんだ。4番街の事務所に来てほしいって。","ENG":"Yes. Rachel told me to pass this on to you. She said you should come to the office on 4th Avenue.","TWN":"對啊，瑞秋請我轉告你，到第四大道的辦公室找她。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇군요. 굳이 요청하지 않아도 이동할 계획이었습니다만.","JPN":"そうですか。わざわざ要請しなくても移動する計画でしたが。","ENG":"I see. I was about to head there anyway.","TWN":"原來如此。就算她不找我，我也正打算要移動。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"아, 그리고 이건 내 개인적인 충고야. 되도록이면 느긋하게 가.","JPN":"ああ、そしてこれは個人的な頼みだ。できればゆっくり行ってくれ。","ENG":"Oh, and here's a bit of personal advice for you. Try to take your time getting there.","TWN":"對了，這是我個人的建議，可以的話盡量放慢腳步。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"레이첼 걔가 그림 그리는 솜씨는 끝내 주지만, 아무리 그래도 시간이 부족할 거거든.","JPN":"レイチェルの絵を描く腕前は最高なんだが、いくらなんでも時間が足りないはずだ。","ENG":"Rachel sure is a great artist, but even she might need a little more time for this.","TWN":"雖然瑞秋的畫畫功力很好，但時間還是有點不夠。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……?","JPN":"……？","ENG":"……?","TWN":"……？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이해하긴 어렵지만, 최대한 반영해 보겠습니다.","JPN":"理解できませんが、最大限に反映してみます。","ENG":"That does not compute, but I will take it into consideration.","TWN":"不太理解，但我盡量。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"……레이첼도 사람이 좋아서 탈이네. 저런 이상한 애까지 챙겨 주고.","JPN":"レイチェルも本当にお節介だな。あんな変わった子まで気遣ってやるなんて。","ENG":"…Rachel's a sweet kid, but sometimes too much for her own good. Taking care of weirdos like that.","TWN":"……瑞秋真的是很善良，連那種怪咖也照顧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"아, 교관님도 건강 진료 받으러 가시죠. 사람들 말이 결핵도 치료해 준답니다.","JPN":"あ、教官も健康診断を受けに行きましょう。結核も治療してくれるそうですよ。","ENG":"Oh, that's right. Why don't you go get your medical exam too, sir? They say you can even get treated for tuberculosis.","TWN":"教官也找醫生義診吧！聽說什麼都能醫呢！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"진료?","JPN":"健康診断？","ENG":"Medical exam?","TWN":"義診？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그러고 보니 오는 길에 못 보던 차에 헬기까지 보이더군. 혹시 무슨 관련이 있나?","JPN":"そういえば見慣れない車にヘリまで見えたな。何かあったのか？","ENG":"Come to think of it, I saw unfamiliar cars and even choppers on the way here. Does that have something to do with it?","TWN":"這樣說來，回來的路有看到陌生的車輛，甚至是直升機，跟這有關係嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"맞습니다. 제프티 바이오테크란 회사에서 갑자기 의료 지원을 해 주러 왔어요.","JPN":"はい、ジェフティ・バイオテックという会社から急に医療支援が来ました。","ENG":"That's right. Some company called Jehuty Biotech popped out of nowhere to provide free medical care.","TWN":"是的，傑夫堤生物科技公司突然說要替大家義診。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"부상자들도 좀 있다던데, 그리로 데려가면 잘 치료해 줄 겁니다.","JPN":"負傷者がいると聞きましたが、そちらに連れて行けばちゃんと治療してくれるでしょう。","ENG":"I heard some of the guys got wounded. They can probably get that taken care of there.","TWN":"我聽說有人受傷的話，可以帶到那裡接受免費治療。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MEMBER2_NPC_MILITIA_NULL","text":{"KOREA":"교관님?","JPN":"教官？","ENG":"Sir?","TWN":"教官？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"아니. 시기가 지나치게 좋다고 생각했을 뿐이야.","JPN":"いや、タイミングが良すぎると思っただけさ。","ENG":"Oh, it's nothing. I just think the timing is too good to be true.","TWN":"沒事，只是時間點真是巧妙。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER2_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"친구들부터 먼저 데리고 가. 뒷정리를 마치는 대로 따라가지.","JPN":"仲間たちを連れて先に行け。俺は後片付けをしてから向かう。","ENG":"Go ahead with the guys. I'll catch up as soon as I finish wrapping things up here.","TWN":"你先帶他們過去吧，我收拾好就過去。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};